+	if (!xlw)
+		return row - xtop;
+	for (i = row; i < xtop; i++)
+		trow -= vi_lnrows(lbuf_get(xb, i));
+	for (i = xtop; i < row; i++)
+		trow += vi_lnrows(lbuf_get(xb, i));
+	return trow;
